import{_ as a,o as i,c as t,ae as o}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Scheduled Dashboard Email Reports","description":"","frontmatter":{"title":"Scheduled Dashboard Email Reports","slug":"scheduled-dashboard-email-reports"},"headers":[],"relativePath":"marketer-hub/scheduled-dashboard-email-reports.md","filePath":"marketer-hub/scheduled-dashboard-email-reports.md"}'),l={name:"marketer-hub/scheduled-dashboard-email-reports.md"};function r(s,e,d,n,c,h){return i(),t("div",null,[...e[0]||(e[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The Scheduled Dashboard Email Reports feature lets you configure an analytics report to be delivered to your email or a colleague’s, which means you don’t have to log into Branch to get the report you need.</p><p>This feature is part of the Saved View functionality, allowing you to manage scheduling that is tied to your saved configurations.</p><p>Based on the schedule you set, an email is delivered to the configuring user and any additional email addresses added as BCCs.</p><p>This email contains a link to download a CSV of the configured table data. The report will include the table data from your Saved View configuration. Please note that reports on line graph visualization charts are not included.</p><h2 id="set-up-a-scheduled-report" tabindex="-1">Set up a scheduled report <a class="header-anchor" href="#set-up-a-scheduled-report" aria-label="Permalink to &quot;Set up a scheduled report&quot;">​</a></h2><p>Follow these steps to configure a scheduled email report:</p><ol><li><p>Navigate to one of the following pages in the Branch Dashboard:</p><ol><li>Overview → Sources</li><li>Ads Analytics → Unified</li><li>Ads Analytics → Activity</li><li>Household → Analytics</li><li>SEO → Analytics</li><li>Email → Activity</li><li>QR Codes → Analytics</li></ol></li><li><p>Either create a new view, or select one of your previously saved views.</p></li><li><p>Click the <strong>calendar icon</strong> that appears next to the dropdown menu of saved views.</p></li><li><p>Configure the delivery schedule for your report. You can choose from the following options:</p><ol><li>Daily</li><li>Every X number of weeks (on a specific day)</li><li>Every X number of months (on a specific day)</li><li>You can also set the schedule to end on a specific date or continue indefinitely.</li></ol></li><li><p>You can now add your colleagues&#39; email addresses to the report delivery. They will be added as BCC recipients on the email. The scheduled email report will always <strong>automatically be sent to the account user</strong>.</p></li><li><p>Click <strong>Done</strong> to save your schedule.</p></li><li><p>Once your schedule is saved and active, the <strong>calendar icon</strong> will turn green and have a checkbox inside of it.</p></li></ol><p>Once the scheduled email report is active, an email with a <strong>link to download the CSV report</strong> will be sent out on the cadence that you configured.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>The email reporting service runs once a day. If you don’t receive your scheduled Dashboard email report, our team will attempt to resolve any failures by the end of the next business day.</p></div><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><details><summary>What data is included in the report?</summary><p>The report will only include the data from the tables in your Saved View configuration. Data from line chart visualizations is not included at this time.</p></details><details><summary>Which analytics pages support scheduled reports?</summary><p>The pages that support scheduled reports are:</p><ol><li>Overview → Sources</li><li>Ads Analytics → Unified</li><li>Ads Analytics → Activity</li><li>Household → Analytics</li><li>SEO → Analytics</li><li>Email → Activity</li><li>QR Codes → Analytics</li></ol></details><details><summary>Can I have more than one scheduled report for the same saved view?</summary><p>No, each saved view can only have one scheduled report associated with it.</p></details><details><summary>What file format is the data delivered in?</summary><p>The email you receive will contain a link to download your report as a CSV file.</p></details>',15)])])}const m=a(l,[["render",r]]);export{p as __pageData,m as default};
